mapper.select:
SELECT COUNT(*)
FROM SHOPPING_CATEGORY
WHERE WS_ID = #{workspaceId, jdbcType=VARCHAR}

mapper.insert:
INSERT INTO SHOPPING_CATEGORY ( CATEGORY_ID
                              , WS_ID
                              , CATEGORY_NM
                              , SORT_ORDER
                              , REGIST_DT
                              , REGIST_ID)
VALUES ( #{categoryId, jdbcType=VARCHAR}
       , #{wsId,       jdbcType=VARCHAR}
       , #{categoryNm, jdbcType=VARCHAR}
       , #{sortOrder,  jdbcType=INTEGER}
       , NOW()
       , #{registId,   jdbcType=VARCHAR})

INSERT INTO SHOPPING_ITEM ( ITEM_ID
                          , WS_ID
                          , CATEGORY_ID
                          , ITEM_NM
                          , QUANTITY
                          , IS_CHECKED
                          , ASSIGNED_USER_ID
                          , REGIST_DT
                          , REGIST_ID)
VALUES ( #{itemId,          jdbcType=VARCHAR}
       , #{wsId,            jdbcType=VARCHAR}
       , #{categoryId,      jdbcType=VARCHAR}
       , #{itemNm,          jdbcType=VARCHAR}
       , #{quantity,        jdbcType=INTEGER}
       , 0
       , #{assignedUserId,  jdbcType=VARCHAR}
       , NOW()
       , #{registId,        jdbcType=VARCHAR})

mapper.update:
UPDATE SHOPPING_ITEM
ITEM_NM = #{itemNm, jdbcType=VARCHAR}, QUANTITY = #{quantity, jdbcType=INTEGER}, IS_CHECKED = #{isChecked, jdbcType=BOOLEAN}, ASSIGNED_USER_ID = #{assignedUserId, jdbcType=VARCHAR}, CATEGORY_ID = #{categoryId, jdbcType=VARCHAR}, UPDT_DT = NOW(), UPDT_ID = #{updtId, jdbcType=VARCHAR}
WHERE ITEM_ID = #{itemId, jdbcType=VARCHAR}

mapper.select:
SELECT COUNT(*) > 0
FROM WORKSPACE_USER
WHERE WS_ID = #{workspaceId, jdbcType=VARCHAR}
  AND USER_ID = #{userId, jdbcType=VARCHAR}
